CREATE TABLE "clientes" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "usuario_id" bigint NOT NULL UNIQUE, "tipo_cliente" varchar(20) NOT NULL, "nombre_empresa" varchar(200) NOT NULL, "nit" varchar(30) NOT NULL, "preferencia_comunicacion" varchar(20) NOT NULL, "rf_probabilidad_retencion" numeric(5, 4) NULL, "rf_segmento_predicho" varchar(30) NOT NULL, "rf_ultima_prediccion" timestamp with time zone NULL, "cantidad_mudanzas" integer NOT NULL, "monto_total_gastado" numeric(12, 2) NOT NULL, "creado_en" timestamp with time zone NOT NULL, "actualizado_en" timestamp with time zone NOT NULL);
